const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = ["gda-deploy-2026-secure", "gda-api-2026-secure", "gda-webhook-secret-2026"];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const idiqs = $input.all().map(function(i) { return i.json; }).filter(function(i) { return i.contract_number; });
if (!idiqs.length) return [{ json: { _hasData: false, _msg: 'No IDIQs tracked' } }];

const queries = [];

for (const idiq of idiqs) {
  const shortName = (idiq.idiq_name || '').split('(')[0].trim().split(' ').slice(0,2).join(' ');

  if (idiq.gda_position === 'holder' || idiq.gda_position === 'teaming') {
    // HOLDERS: search contract number for task orders
    queries.push({ json: { idiq_id: idiq.id, contract_number: idiq.contract_number, idiq_name: idiq.idiq_name, agency: idiq.agency, gda_position: idiq.gda_position, search_term: idiq.contract_number, search_type: 'task_order', _hasData: true }});
    // Plus first keyword if available
    const kw = (idiq.sam_search_keywords || [])[0];
    if (kw && kw !== idiq.contract_number) {
      queries.push({ json: { idiq_id: idiq.id, contract_number: idiq.contract_number, idiq_name: idiq.idiq_name, agency: idiq.agency, gda_position: idiq.gda_position, search_term: kw, search_type: 'task_order', _hasData: true }});
    }
  } else if (idiq.gda_position === 'targeting') {
    // TARGETING: 2 searches — on-ramp + open season
    queries.push({ json: { idiq_id: idiq.id, contract_number: idiq.contract_number, idiq_name: idiq.idiq_name, agency: idiq.agency, gda_position: idiq.gda_position, search_term: shortName + ' on-ramp', search_type: 'on_ramp', _hasData: true }});
    queries.push({ json: { idiq_id: idiq.id, contract_number: idiq.contract_number, idiq_name: idiq.idiq_name, agency: idiq.agency, gda_position: idiq.gda_position, search_term: shortName + ' additional awardee', search_type: 'on_ramp', _hasData: true }});
  }
}

// Deduplicate
const seen = new Set();
return queries.filter(function(q) {
  const key = q.json.search_term;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const allItems = $input.all();
const results = [];
const seen = new Set();
const EIS_NAICS = ['541330','541511','541512','541513','541519','541611','541690','541715','541990','611430','561210','561110'];
const TARGET_AGENCIES = ['socom','tradoc','peo stri','inscom','cybercom','disa','indopacom','mda','missile defense','faa'];
const ON_RAMP_SIGNALS = /on.?ramp|open season|additional awardee|additional award|new entrant|reopen|fair opportunity notice/i;

for (const item of allItems) {
  if (item.json.error || !item.json.opportunitiesData) continue;
  const opps = item.json.opportunitiesData || [];
  for (const opp of opps) {
    const id = opp.solicitationNumber || opp.noticeId || '';
    if (!id || seen.has(id)) continue;
    const title = (opp.title || '').toLowerCase();
    if (/janitorial|custodial|food service|mowing/.test(title)) continue;
    seen.add(id);
    const hier = opp.organizationHierarchy || [];
    const agency = hier.length > 0 ? hier[0].name : (opp.fullParentPathName || '');
    const naics = opp.naicsCode || '';
    const sa = (opp.typeOfSetAsideDescription || '').toLowerCase();
    const fullText = title + ' ' + (opp.description || '').toLowerCase();

    // Detect if this is an on-ramp announcement
    const isOnRamp = ON_RAMP_SIGNALS.test(fullText) || ON_RAMP_SIGNALS.test(opp.title || '');

    // GDA Score
    let score = 0;
    score += EIS_NAICS.includes(naics) ? 15 : naics.startsWith('541') ? 5 : 0;
    let mp = 0;
    if (/seta|systems engineering/.test(title)) mp = 15;
    if (/simulat|training/.test(title)) mp = Math.max(mp, 12);
    if (/missile|defense|shield/.test(title)) mp = Math.max(mp, 12);
    if (/cyber|intel/.test(title)) mp = Math.max(mp, 10);
    if (/it support|cloud/.test(title)) mp = Math.max(mp, 8);
    score += Math.min(mp, 15);
    score += 10; // OU fit for tracked IDIQ
    score += /sdvosb/.test(sa) ? 10 : /8\(a\)/.test(sa) ? 10 : /small business/.test(sa) ? 8 : 3;
    score += 15; // tracked IDIQ relationship
    score += /small business/.test(sa) ? 7 : 3;
    score += 5;
    score += isOnRamp ? 10 : 8; // on-ramp bonus
    score += 5;
    score = Math.min(Math.max(Math.round(score), 0), 100);

    // On-ramp gets PURSUE label automatically
    const label = isOnRamp ? 'PURSUE' : (score >= 80 ? 'PURSUE' : score >= 60 ? 'EVALUATE' : score >= 40 ? 'MONITOR' : 'PASS');
    if (isOnRamp) score = Math.max(score, 85); // floor at 85 for on-ramps

    const prefix = isOnRamp ? '[ON-RAMP] ' : '[TO] ';
    const stage = isOnRamp ? 'On-Ramp' : 'Identified';

    results.push({ json: {
      solicitation_number: id,
      opp_title: prefix + (opp.title || '').substring(0, 470),
      agency: agency,
      dept: hier.length > 0 ? hier[0].name : '',
      naics_code: naics,
      set_aside: opp.typeOfSetAsideDescription || '',
      response_deadline: opp.responseDeadLine || null,
      source_url: opp.uiLink || ('https://sam.gov/opp/' + (opp.noticeId || '') + '/view'),
      data_source: isOnRamp ? 'IDIQ On-Ramp Detection' : 'IDIQ TO Monitor',
      govtribe_id: opp.noticeId || '',
      gda_score: score,
      gda_label: label,
      eis_fit_score: score,
      stage: stage,
      ai_analysis: (isOnRamp ? 'ON-RAMP DETECTED: ' : 'Task Order under IDIQ: ') + ' | Vehicle: Unknown (cross-ref with IDIQ tracker)',
      _hasData: true
    }});
  }
}
if (!results.length) return [{ json: { _hasData: false, _msg: 'No new task orders or on-ramps found' } }];
return results;

// Count TOs per IDIQ and update stats
const items = $input.all();
const idiqCounts = {};
for (const item of items) {
  const cn = item.json._contract_number;
  if (cn) {
    if (!idiqCounts[cn]) idiqCounts[cn] = 0;
    idiqCounts[cn]++;
  }
}
// We can't run dynamic SQL per IDIQ in code node easily,
// but we log the counts for the summary
return [{ json: { _hasData: true, idiq_to_counts: idiqCounts, total_new_tos: items.length } }];

const items = $input.all();
const first = items[0]?.json || {};
const summary = {
  status: 'ok',
  workflow: 'GDA.sched.idiq-to-monitor',
  new_task_orders: first.total_new_tos || 0,
  idiq_breakdown: first.idiq_to_counts || {},
  timestamp: new Date().toISOString()
};
return [{ json: summary }];
